# home-manager module for yokushi.
#
# Usage in flake-based home-manager config:
#
#   inputs.yokushi.url = "github:daaa1k/yokushi";
#
#   home-manager.sharedModules = [ inputs.yokushi.homeManagerModules.yokushi ];
#
# Then in your home.nix:
#
#   programs.yokushi = {
#     enable = true;
#     settings.rules = [
#       { pattern = "git push"; message = "Use pull requests."; }
#     ];
#   };
flake:
{ config, pkgs, lib, ... }:
let
  cfg = config.programs.yokushi;

  # Build a rule attribute set, omitting null optional fields.
  mkRuleAttr = rule:
    { inherit (rule) pattern message; }
    // lib.optionalAttrs (rule.tool != null) { tool = rule.tool; }
    // lib.optionalAttrs (rule.field != null) { field = rule.field; };

  configData = {
    version = "1";
    agents = lib.mapAttrs (_: a: { output = a.output; }) cfg.settings.agents;
    rules = map mkRuleAttr cfg.settings.rules;
  };

  generatedConfig = (pkgs.formats.yaml { }).generate "yokushi-config.yaml" configData;
in
{
  options.programs.yokushi = {
    enable = lib.mkEnableOption "yokushi AI agent hook validator";

    package = lib.mkOption {
      type = lib.types.package;
      default = flake.packages.${pkgs.system}.yokushi;
      defaultText = lib.literalExpression "yokushi.packages.\${pkgs.system}.yokushi";
      description = "The yokushi package to install.";
    };

    settings = {
      agents = lib.mkOption {
        type = lib.types.attrsOf (lib.types.submodule {
          options.output = lib.mkOption {
            type = lib.types.enum [ "json" "exit" ];
            description = "Output mode: json (stdout JSON + exit 0) or exit (stderr + exit 2).";
          };
        });
