{
  description = "yokushi - AI agent PreToolUse hook validator";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};

        yokushi = pkgs.rustPlatform.buildRustPackage {
          pname = "yokushi";
          version = "0.1.0";
          src = self;
          cargoLock.lockFile = ./Cargo.lock;
          meta = with pkgs.lib; {
            description = "AI agent PreToolUse hook validator";
            homepage = "https://github.com/daaa1k/yokushi";
            license = licenses.mit;
            mainProgram = "yokushi";
          };
        };
      in
      {
        packages = {
          inherit yokushi;
          default = yokushi;
        };

        devShells.default = pkgs.mkShell {
          buildInputs = with pkgs; [ rustc cargo clippy rustfmt ];
        };
      }
    ) // {
      homeManagerModules = {
        yokushi = import ./nix/home-manager.nix self;
        default = import ./nix/home-manager.nix self;
      };
    };
}

