{
  description = "oxsb — Cross-platform sandbox wrapper";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
    flake-utils.url = "github:numtide/flake-utils";
    crane.url = "github:ipetkov/crane";
  };

  outputs = { self, nixpkgs, flake-utils, crane }:
    let
      # Home Manager module — system-agnostic, exported at the top level.
      #
      # Usage in a Home Manager configuration:
      #
      #   inputs.oxsb.url = "github:daaa1k/oxsb";
      #
      #   { inputs, ... }: {
      #     imports = [ inputs.oxsb.homeManagerModules.default ];
      #     programs.oxsb = {
      #       enable = true;
      #       settings = {
      #         backend.auto = true;
      #         write_allow = [
      #           { path = "$HOME/.config"; }
      #           { path = "/tmp"; }
      #         ];
      #         env.set.IN_SANDBOX = "1";
      #       };
      #     };
      #   }
      hmModule = { config, lib, pkgs, ... }:
        let
          cfg = config.programs.oxsb;
          yamlFormat = pkgs.formats.yaml { };
        in
        {
          options.programs.oxsb = {
            enable = lib.mkEnableOption "oxsb cross-platform sandbox wrapper";

            package = lib.mkOption {
              type = lib.types.package;
              default = self.packages.${pkgs.system}.default;
              defaultText = lib.literalExpression "oxsb.packages.\${pkgs.system}.default";
              description = "The oxsb package to install.";
            };

            settings = lib.mkOption {
              type = yamlFormat.type;
              default = { };
              description = ''
                Configuration for oxsb written to
                {file}`$XDG_CONFIG_HOME/oxsb/config.yaml`.

                Top-level keys mirror the YAML schema:
                `backend`, `write_allow`, `bubblewrap`, `seatbelt`, `env`.
                See {file}`examples/config_default.yaml` in the oxsb repository
                for a fully-annotated reference.
              '';
              example = lib.literalExpression ''
                {
                  backend.auto = true;
                  write_allow = [
                    { path = "$HOME/.config"; }
                    { path = "$HOME/.cache"; }
                    { path = "$HOME/.local/share"; }
                    { path = "/tmp"; }
                  ];
                  env.set.IN_SANDBOX = "1";
                }
              '';
            };
          };

          config = lib.mkIf cfg.enable {
            home.packages = [ cfg.package ];

            xdg.configFile."oxsb/config.yaml" = lib.mkIf (cfg.settings != { }) {
              source = yamlFormat.generate "oxsb-config.yaml" cfg.settings;
            };
          };
        };
    in
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        craneLib = crane.mkLib pkgs;

        # Arguments shared between dependency pre-build and the final build.
        commonArgs = {
          src = craneLib.cleanCargoSource ./.;
          strictDeps = true;

          # libiconv is required on macOS (see build.rs).
          buildInputs = pkgs.lib.optionals pkgs.stdenv.isDarwin [
            pkgs.libiconv
          ];
        };

        # Pre-build only the dependencies to maximise cache reuse.
        cargoArtifacts = craneLib.buildDepsOnly commonArgs;

        oxsb = craneLib.buildPackage (commonArgs // {
          inherit cargoArtifacts;
        });
      in
      {
        # --- packages ---------------------------------------------------
        packages = {
          default = oxsb;
          inherit oxsb;
        };

        # --- checks (run by `nix flake check`) --------------------------
        checks = {
          # Build the package itself.
          inherit oxsb;

          # Run clippy with --deny warnings.
          oxsb-clippy = craneLib.cargoClippy (commonArgs // {
            inherit cargoArtifacts;
            cargoClippyExtraArgs = "--all-targets -- --deny warnings";
          });

          # Run the test suite.
          oxsb-test = craneLib.cargoTest (commonArgs // {
            inherit cargoArtifacts;
          });
        };

        # --- devShell ---------------------------------------------------
        devShells.default = craneLib.devShell {
          checks = self.checks.${system};
          packages = [
            pkgs.rust-analyzer
            pkgs.rustfmt
          ];
        };
      }
    ) // {
      # --- Home Manager module (system-agnostic) ----------------------
      homeManagerModules.default = hmModule;
    };
}

content.text:
主要な違いを整理します。

---

## 1. ビルドシステム

| | yokushi | oxsb |
|---|---|---|
| ツール | `rustPlatform.buildRustPackage` (nixpkgs 組み込み) | `crane` (サードパーティ input) |
| ソース指定 | `src = self` (全ファイル) | `craneLib.cleanCargoSource ./.` (Cargo に必要なファイルのみ) |
| 依存キャッシュ | なし（毎回全ビルド） | `buildDepsOnly` で依存だけ先にビルドしてキャッシュ |

crane は依存クレートと自分のコードを別 derivation に分けてビルドするため、**自分のコードだけ変えた場合に依存の再ビルドをスキップ**できます。

## 2. `checks` 出力の有無

oxsb には `nix flake check` で走る3つのチェックがあります：

```nix
checks = {
  inherit oxsb;                 # ビルド
  oxsb-clippy = craneLib.cargoClippy ...;  # lint
  oxsb-test   = craneLib.cargoTest ...;    # テスト
};
```

yokushi にはこれがなく、`nix flake check` はビルドの評価のみ確認します。

## 3. devShell の構成

```nix
# yokushi — 手動でツールを列挙
devShells.default = pkgs.mkShell {
  buildInputs = with pkgs; [ rustc cargo clippy rustfmt ];
};

# oxsb — checks から自動的にツールを引き込む
devShells.default = craneLib.devShell {
  checks = self.checks.${system};  # clippy/test に必要なものが自動で入る
  packages = [ pkgs.rust-analyzer pkgs.rustfmt ];
};
```

## 4. home-manager モジュールの定義場所とパッケージ参照

```nix
# yokushi — 別ファイル、flake を引数で明示的に受け取る
homeManagerModules.yokushi = import ./nix/home-manager.nix self;
# home-manager.nix 内: flake.packages.${pkgs.system}.yokushi

# oxsb — flake.nix 内の let で直接定義、self をクロージャで参照
hmModule = { config, lib, pkgs, ... }: ...;
# モジュール内: self.packages.${pkgs.system}.default
```

## 5. settings オプションの型設計

これが最も大きな設計の違いです：

```nix
# yokushi — 各フィールドを submodule で厳密に型定義
rules = lib.mkOption {
  type = lib.types.listOf (lib.types.submodule {
    options = { tool = ...; field = ...; pattern = ...; message = ...; };
  });
};

# oxsb — yamlFormat.type でフリーフォームの Nix 値を受け付ける
settings = lib.mkOption {
  type = yamlFormat.type;  # any = attrs/list/string/number/bool
};
```

oxsb の `yamlFormat.type` は任意の Nix 値を受け付けるため、**スキーマに縛られず設定できる柔軟性**があります。一方 yokushi のアプローチは**補完や型チェックが効く**という利点があります。

---

## どちらを参考にすべきか

yokushi に oxsb の手法を取り入れるなら：

- **crane の導入** → ビルドの再利用性が上がるが、input が増える
- **`checks` の追加** → `nix flake check` で CI 相当の検証ができる
- **`settings` を `yamlFormat.type` に変更** → ユーザーが自由に YAML 構造を書ける（ただし型チェックはなくなる）

